package com.example.projectbackend.controller;

import com.example.projectbackend.dto.ReimbursementDetailDto;
import com.example.projectbackend.dto.ReimbursementListItemDto;
import com.example.projectbackend.dto.ReimbursementUpsertRequest;
import com.example.projectbackend.service.ReimbursementService;
import jakarta.validation.Valid;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/reimbursements")
public class ReimbursementController {

    private final ReimbursementService reimbursementService;

    public ReimbursementController(ReimbursementService reimbursementService) {
        this.reimbursementService = reimbursementService;
    }

    @GetMapping
    public List<ReimbursementListItemDto> list(@RequestParam(required = false) String id,
                                               @RequestParam(required = false) String title,
                                               @RequestParam(required = false) String reason,
                                               @RequestParam(required = false) String companyId,
                                               @RequestParam(required = false) String departmentId,
                                               @RequestParam(required = false) String reimburserId,
                                               @RequestParam(required = false) String businessTypeId) {
        return reimbursementService.list(id, title, reason, companyId, departmentId, reimburserId, businessTypeId);
    }

    @GetMapping("/{id}")
    public ReimbursementDetailDto detail(@PathVariable String id) {
        return reimbursementService.detail(id);
    }

    @PostMapping
    public Map<String, Object> create(@Valid @RequestBody ReimbursementUpsertRequest request) {
        String id = reimbursementService.create(request);
        Map<String, Object> response = new HashMap<>();
        response.put("id", id);
        return response;
    }

    @PutMapping("/{id}")
    public Map<String, Object> update(@PathVariable String id, @Valid @RequestBody ReimbursementUpsertRequest request) {
        reimbursementService.update(id, request);
        Map<String, Object> response = new HashMap<>();
        response.put("id", id);
        return response;
    }

    @PostMapping("/{id}/submit")
    public Map<String, Object> submit(@PathVariable String id) {
        reimbursementService.submit(id);
        Map<String, Object> response = new HashMap<>();
        response.put("id", id);
        response.put("status", 1);
        return response;
    }

    @PostMapping("/{id}/void")
    public Map<String, Object> voidDocument(@PathVariable String id) {
        reimbursementService.voidDocument(id);
        Map<String, Object> response = new HashMap<>();
        response.put("id", id);
        response.put("status", 2);
        return response;
    }
}

package com.example.projectbackend.controller;

import com.example.projectbackend.dto.ReimbursementDetailDto;
